    .flow-panel { display: none; max-width: 1040px; margin: 0 auto; }
    .flow-panel.active { display: block; }

    /* ������ �쓲由� �뿤�뜑 ������ */
    .flow-header {
      background: #161b22; border: 1px solid #30363d;
      border-radius: 10px; padding: 14px 18px; margin-bottom: 18px;
      display: flex; align-items: flex-start; gap: 12px;
    }
    .flow-num {
      width: 34px; height: 34px; border-radius: 8px; flex-shrink: 0;
      background: #1f2937; border: 1.5px solid #3b82f6;
      display: flex; align-items: center; justify-content: center;
      font-size: 15px; font-weight: 700; color: #60a5fa;
    }
    .flow-title { font-size: 14px; font-weight: 700; color: #f0f6fc; margin-bottom: 4px; }
    .flow-desc  { font-size: 11px; color: #8b949e; line-height: 1.6; }

    /* ������ 而댄룷�꼳�듃 媛쒖슂 諛� ������ */
    .comp-bar {
