      background: #0d1117; border: 1px solid #21262d;
      border-radius: 10px; padding: 12px 16px; margin-bottom: 20px;
      overflow-x: auto; gap: 0;
    }
    .comp-node { display: flex; flex-direction: column; align-items: center; gap: 4px; flex-shrink: 0; }
    .comp-badge {
      padding: 5px 11px; border-radius: 6px;
      font-size: 10px; font-weight: 700; white-space: nowrap; border: 1px solid;
    }
    .cb-app     { background: #2d1810; border-color: #92400e; color: #f97316; }
    .cb-alloy   { background: #0d1f12; border-color: #166534; color: #4ade80; }
    .cb-loki    { background: #0d1f12; border-color: #166534; color: #34d399; }
    .cb-prom    { background: #2d1810; border-color: #92400e; color: #f97316; }
    .cb-grafana { background: #1a1000; border-color: #b45309; color: #f59e0b; }
    .cb-llm     { background: #1a0a2e; border-color: #5b21b6; color: #c084fc; }
    .cb-ollama  { background: #0f0a2a; border-color: #7c3aed; color: #a78bfa; }
    .cb-user    { background: #0c1929; border-color: #1d4ed8; color: #60a5fa; }
    .cb-result  { background: #0d1f12; border-color: #166534; color: #4ade80; }
    .comp-label { font-size: 9px; color: #6e7681; }

    .bar-arrow {
      display: flex; flex-direction: column; align-items: center;
      padding: 0 5px; flex-shrink: 0; padding-bottom: 14px;
    }
    .bar-line {
      width: 36px; height: 2px; background: #21262d; position: relative; margin-top: 10px;
    }
    .bar-line::after {
      content: '�뼳'; position: absolute; right: -9px; top: -8px;
      font-size: 10px; color: #444c56;
    }
    .bar-proto { font-size: 9px; color: #444c56; margin-top: 5px; font-family: monospace; }

    /* ������ �떒怨� 紐⑸줉 ������ */
    .steps { display: flex; flex-direction: column; }

    .step { display: flex; gap: 0; }

    .step-connector {
      display: flex; flex-direction: column; align-items: center; width: 38px; flex-shrink: 0;
    }
    .step-dot {
      width: 28px; height: 28px; border-radius: 50%;
      display: flex; align-items: center; justify-content: center;
      font-size: 11px; font-weight: 700; flex-shrink: 0; border: 2px solid; z-index: 1;
    }
